mapper.select:
SELECT req.inchikey, t.symbol, t.gene_entrez_id AS geneEntrezId, t.uniprot_id AS uniprotId, t.description FROM ( SELECT DISTINCT params.inchikey FROM (
SELECT #{inchikey} AS inchikey
) params ) req INNER JOIN compound_target_rel ct ON ct.inchikey = req.inchikey INNER JOIN targets t ON ct.tcm_tar_id = t.tcm_tar_id ORDER BY req.inchikey, t.symbol ASC
